code = """import json

# Get paths
funding_path = locals()['var_function-call-1424370091685766711']
docs_path = locals()['var_function-call-10286396622452696184']

# Load data
with open(funding_path, 'r') as f:
    funding_records = json.load(f)
    
# Create funding map (> 50k)
# Use a map for exact lookup and a list for fuzzy
funding_map = {}
for r in funding_records:
    try:
        amt = float(r['Amount'])
        funding_map[r['Project_Name'].strip()] = amt
    except:
        pass

with open(docs_path, 'r') as f:
    docs = json.load(f)

# Use index 0 (latest)
latest_doc = docs[0]
text = latest_doc.get('text', '')
lines = text.splitlines()

candidates = set()
in_design = False

debug_log = []

for line in lines:
    line = line.strip()
    if not line: continue
    
    if 'Capital Improvement Projects (Design)' in line:
        in_design = True
        debug_log.append("Enter Design")
        continue
        
    if 'Capital Improvement Projects' in line and 'Design' not in line:
        if in_design: debug_log.append(f"Exit Design at {line}")
        in_design = False
    if 'Disaster Recovery Projects' in line:
        if in_design: debug_log.append(f"Exit Design at {line}")
        in_design = False
        
    if in_design:
        if line.startswith('(cid:') or line.startswith('Page ') or line.startswith('Agenda Item'): continue
        if any(x in line.lower() for x in ['prepared by', 'approved by', 'date prepared', 'meeting date', 'subject:', 'recommended action:', 'discussion:']): continue
        if 'Updates:' in line or 'Schedule:' in line: continue
        if line.startswith('Item') or line.startswith('To:') or line.startswith('From:'): continue
        if len(line) > 100 or line.endswith('.'): continue
        
        name = line.strip()
        if len(name) < 5: continue
        candidates.add(name)

# Match against funding
matches = []
matched_names = set()

# Candidates found
# We need to match these to funding_map
# We also have funding amount check here
valid_count = 0

# Check exact and fuzzy
# I'll create a helper to check
def check_funding(name):
    # Exact
    if name in funding_map:
        return funding_map[name]
    # Fuzzy/Substring
    for fname, amt in funding_map.items():
        if name.lower() == fname.lower(): return amt
        # Substring
        if (name in fname or fname in name) and len(name)>10 and len(fname)>10:
            return amt
    return 0

final_list = []
for cand in candidates:
    amt = check_funding(cand)
    if amt > 50000:
        final_list.append((cand, amt))
        
print('__RESULT__:')
print(json.dumps({'count': len(final_list), 'list': final_list, 'candidates': list(candidates), 'debug': debug_log}))"""

